(function(){var sliders=document.querySelectorAll("[data-hero-slider]");if(!sliders.length){return}sliders.forEach(function(slider){var slides=slider.querySelectorAll("[data-hero-slide]");var prev=slider.querySelector("[data-hero-prev]");var next=slider.querySelector("[data-hero-next]");var index=0;var timer=null;if(slides.length<2){return}var show=function(newIndex){slides[index].classList.remove("is-active");index=(newIndex+slides.length)%slides.length;slides[index].classList.add("is-active")};var start=function(){timer=window.setInterval(function(){show(index+1)},5000)};var restart=function(){if(timer){window.clearInterval(timer)}start()};prev&&prev.addEventListener("click",function(){show(index-1);restart()});next&&next.addEventListener("click",function(){show(index+1);restart()});start()})})();
